        "question": [
          "this data set is called 'positions from iban'\n",
          "count how many positions were opened per day in the last 2 weeks in 'positions from iban'"
        ],
        "sql": [
          "SELECT\n",
          "  DATE(dp.OpenOccurred) AS OpenDate,\n",
          "  COUNT(dp.PositionID) AS PositionsCount\n",
          "FROM\n",
          "  main.dwh.dim_position dp\n",
          "  INNER JOIN main.trading.bronze_iban_trade_ordertoexternaloperation oteo ON dp.OrderID = oteo.OrderID\n",
          "  INNER JOIN main.billing.bronze_moneybusdb_moneybus_transactions mbt ON oteo.ReferenceID = mbt.ReferenceID\n",
          "  INNER JOIN main.billing.bronze_etoro_billing_deposit bed ON mbt.ID = bed.ExTransactionID\n",
          "WHERE\n",
          "  oteo.ReferenceID IS NOT NULL\n",
          "  AND dp.OpenOccurred >= date_sub(current_date, 14)\n",
          "  AND bed.FlowID = 1\n",
          "  AND bed.DepositTypeID = 4\n",
          "GROUP BY\n",
          "  DATE(dp.OpenOccurred)"
        ]
      }
    ]
  }
